where is_delete = 0

    and id = #{condition.id}
    and account_id = #{condition.accountId}
    and user_id = #{condition.userId}

        and account_name like concat('%', #{condition.accountName}, '%')

    and phone = #{condition.phone}
    and lower(email) = lower(#{condition.email})

        and account_status = #{condition.accountStatus}


        and registered_channel = #{condition.registeredChannel}

